terraform {
  # The pre-1.16 world: count/for_each cannot depend on values unknown at plan,
  # which is exactly why the module needs a separate, plan-known `provided` flag.
  required_version = ">= 1.5.0"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = ">= 3.0"
    }
  }
}

provider "aws" {
  region = var.region
}
=== examples/terraform-deferred-actions/02-after/providers.tf ===
terraform {
  # Deferred actions (unknown count/for_each) are native in 1.16 - no experiments
  # block - but the alpha CLI still requires the -allow-deferral flag on plan/apply
  # (without it, the plan errors on the unknown value). The alpha is pinned via
  # .terraform-version; prerelease constraints aren't allowed here, so match the
  # 1.16.0 version core (alpha builds satisfy it by their core version).
  required_version = ">= 1.16.0"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 5.0"
    }
    random = {
      source  = "hashicorp/random"
      version = ">= 3.0"
    }
  }
}

provider "aws" {
  region = var.region
}

