=== examples/terraform-deferred-actions/01-before/main.tf ===
# BEFORE (Terraform < 1.16): the KMS key ARN is unknown at plan, and count/for_each
# cannot depend on unknown values. So we cannot let the module derive "is a key
# provided?" from `arn != null`. We must thread a second, plan-known boolean
# (`provided`) alongside the ARN - redundant, and able to disagree with `arn`.

resource "random_id" "suffix" {
  byte_length = 4
}

# KMS key created in this root module; its ARN is unknown until apply.
resource "aws_kms_key" "root" {
  description             = "Root-managed KMS key for the deferred-actions S3 demo (before)"
  deletion_window_in_days = 7
}

module "bucket" {
  source = "./modules/s3-bucket-encrypted"

  bucket_name = "${var.bucket_prefix}-${random_id.suffix.hex}"

  # `provided = true` is a literal known at plan -> the module's count is
  # determinable, even though `arn` itself is unknown until apply.
  kms = {
    arn      = aws_kms_key.root.arn
    provided = true
  }
}

=== examples/terraform-deferred-actions/01-before/modules/s3-bucket-encrypted/main.tf ===
# count is keyed on the explicit, plan-known `var.kms.provided` flag - NOT on
# `var.kms.arn != null`, which would be unknown at plan and make `terraform plan`
# fail pre-1.16 ("Invalid count argument ... value depends on resource attributes
# that cannot be determined until apply"). That limitation is the whole reason the
# separate boolean exists.
data "aws_kms_key" "provided" {
  # DEMO segment 2 - starting point (1.15 OK): count keyed on the plan-known provided boolean.
  count = var.kms.provided ? 1 : 0
  # DEMO segment 2 - "it breaks": ARN unknown at plan -> Invalid count argument
  # count = var.kms.arn != null ? 1 : 0
  key_id = var.kms.arn
}

resource "aws_s3_bucket" "this" {
  bucket = var.bucket_name
  tags   = var.tags
}

resource "aws_s3_bucket_public_access_block" "this" {
  bucket                  = aws_s3_bucket.this.id
  block_public_acls       = true
  block_public_policy     = true
  ignore_public_acls      = true
  restrict_public_buckets = true
}

resource "aws_s3_bucket_server_side_encryption_configuration" "this" {
  bucket = aws_s3_bucket.this.id

  rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "aws:kms"
      # null => S3's default managed key (aws/s3); otherwise the validated ARN.
      kms_master_key_id = one(data.aws_kms_key.provided[*].arn)
    }
    bucket_key_enabled = true
  }
}

=== examples/terraform-deferred-actions/01-before/modules/s3-bucket-encrypted/outputs.tf ===
output "bucket_id" {
  description = "ID (name) of the created bucket."
  value       = aws_s3_bucket.this.id
}

output "bucket_arn" {
  description = "ARN of the created bucket."
  value       = aws_s3_bucket.this.arn
}

output "encryption_kms_key_arn" {
  description = "KMS key ARN used for encryption; null when using S3's default managed key."
  value       = one(data.aws_kms_key.provided[*].arn)
}

=== examples/terraform-deferred-actions/01-before/modules/s3-bucket-encrypted/variables.tf ===
variable "bucket_name" {
  description = "Name of the S3 bucket to create."
  type        = string
}

variable "kms" {
  description = <<-EOT
    KMS settings for bucket encryption. Pre-1.16, `provided` (a value known at
    plan time) is REQUIRED separately from `arn` (which may be unknown at plan):
    count/for_each cannot depend on unknown values, so the module cannot infer
    "is a key provided?" from `arn != null`. When `provided` is false the bucket
    falls back to S3's default SSE-KMS managed key (aws/s3).
  EOT
  type = object({
    arn      = optional(string)
    provided = bool
  })
  default = {
    arn      = null
    provided = false
  }
}

variable "tags" {
  description = "Tags to apply to the bucket."
  type        = map(string)
  default     = {}
}

=== examples/terraform-deferred-actions/01-before/modules/s3-bucket-encrypted/versions.tf ===
terraform {
  required_version = ">= 1.5.0"

  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = ">= 5.0"
    }
  }
}

=== examples/terraform-deferred-actions/01-before/outputs.tf ===
output "root_kms_key_arn" {
  description = "ARN of the KMS key created in the root module."
  value       = aws_kms_key.root.arn
}

output "bucket" {
  description = "Bucket encrypted with the root-created KMS key."
  value = {
    arn         = module.bucket.bucket_arn
    kms_key_arn = module.bucket.encryption_kms_key_arn
  }
